import { useEffect, useState } from "react";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function Menu() {
  const [foods, setFoods] = useState([]);
  const [activeCategory, setActiveCategory] = useState("all");

  useEffect(() => {
    fetchFoods();
  }, []);

  const fetchFoods = async () => {
    try {
      const res = await axios.get(`${API_BASE}/api/food/`);
      setFoods(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const categories = [
    "all",
    "bread",
    "drinks",
    "veg",
    "non-veg",
    "dessert",
  ];

  const filteredFoods =
    activeCategory === "all"
      ? foods
      : foods.filter((f) => f.category === activeCategory);

  return (
    <div className="menu-page">
      <style>{`
        .menu-page {
          background: #0e0d0d;
          min-height: 100vh;
          padding: 80px 24px;
          color: #f1f1f1;
          font-family: 'Montserrat', 'Segoe UI', sans-serif;
        }

        .menu-header {
          text-align: center;
          margin-bottom: 50px;
        }

        .menu-header h1 {
          color: #c89d5c;
          font-size: 42px;
          margin-bottom: 10px;
        }

        .menu-header p {
          color: #aaa;
          font-size: 15px;
        }

        .category-tabs {
          display: flex;
          justify-content: center;
          gap: 16px;
          flex-wrap: wrap;
          margin-bottom: 40px;
        }

        .category-tabs button {
          background: transparent;
          border: 1px solid #c89d5c;
          color: #c89d5c;
          padding: 8px 18px;
          border-radius: 20px;
          cursor: pointer;
          font-size: 13px;
        }

        .category-tabs button.active {
          background: #c89d5c;
          color: #111;
        }

        .menu-grid {
          max-width: 1200px;
          margin: auto;
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
          gap: 26px;
        }

        .menu-card {
          background: rgba(30, 28, 28, 0.7);
          backdrop-filter: blur(10px);
          border-radius: 18px;
          overflow: hidden;
          transition: transform 0.25s ease;
          border: 1px solid rgba(200, 157, 92, 0.2);
        }

        .menu-card:hover {
          transform: translateY(-6px);
        }

        .menu-card img {
          width: 100%;
          height: 190px;
          object-fit: cover;
        }

        .menu-content {
          padding: 18px;
        }

        .menu-content h3 {
          color: #f5e7cf;
          font-size: 18px;
          margin-bottom: 6px;
        }

        .menu-content .category {
          font-size: 12px;
          text-transform: uppercase;
          color: #c89d5c;
          margin-bottom: 10px;
          letter-spacing: 1px;
        }

        .menu-content .price {
          font-size: 16px;
          font-weight: 600;
          color: #c89d5c;
        }

        @media (max-width: 600px) {
          .menu-header h1 {
            font-size: 32px;
          }
        }
      `}</style>

      <div className="menu-header">
        <h1>Our Menu</h1>
        <p>Carefully crafted dishes for your perfect stay</p>
      </div>

      <div className="category-tabs">
        {categories.map((cat) => (
          <button
            key={cat}
            className={activeCategory === cat ? "active" : ""}
            onClick={() => setActiveCategory(cat)}
          >
            {cat.toUpperCase()}
          </button>
        ))}
      </div>

      <div className="menu-grid">
        {filteredFoods.length === 0 ? (
          <p style={{ textAlign: "center", gridColumn: "1/-1" }}>
            No items available
          </p>
        ) : (
          filteredFoods.map((food) => (
            <div className="menu-card" key={food.id}>
              <img
                src={food.image_url || `${API_BASE}${food.image}`}
                alt={food.name}
              />
              <div className="menu-content">
                <div className="category">{food.category}</div>
                <h3>{food.name}</h3>
                <div className="price">₹{food.price}</div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
